import{_ as s,c as n,o as a,a5 as p}from"./chunks/framework.DwbewbAn.js";const g=JSON.parse('{"title":"MySQL checkpoint深入分析","description":"","frontmatter":{},"headers":[],"relativePath":"doc/数据库/Mysql/面试总结/MySQL checkpoint深入分析.md","filePath":"packages/doc/src/数据库/Mysql/面试总结/MySQL checkpoint深入分析.md","lastUpdated":1711622925000}'),e={name:"doc/数据库/Mysql/面试总结/MySQL checkpoint深入分析.md"},l=p(`<h1 id="mysql-checkpoint深入分析" tabindex="-1"><a href="https://www.cnblogs.com/geaozhang/p/7341333.html" target="_blank" rel="noreferrer">MySQL checkpoint深入分析</a> <a class="header-anchor" href="#mysql-checkpoint深入分析" aria-label="Permalink to &quot;[MySQL checkpoint深入分析](https://www.cnblogs.com/geaozhang/p/7341333.html)&quot;">​</a></h1><blockquote><p>1、<a href="https://www.cnblogs.com/geaozhang/p/7341333.html#richangguanzhudian" target="_blank" rel="noreferrer">日常关注点的问题</a></p><p>2、<a href="https://www.cnblogs.com/geaozhang/p/7341333.html#rizhidian" target="_blank" rel="noreferrer">日志点分析</a></p><p>3、<a href="https://www.cnblogs.com/geaozhang/p/7341333.html#checkpoint" target="_blank" rel="noreferrer">checkpoint</a>：脏页刷盘的检查点</p><p>4、<a href="https://www.cnblogs.com/geaozhang/p/7341333.html#fuzzy" target="_blank" rel="noreferrer">模糊检查点发生条件</a></p><p>1、<a href="https://www.cnblogs.com/geaozhang/p/7341333.html#master" target="_blank" rel="noreferrer">master thread checkpoint</a></p><p>2、<a href="https://www.cnblogs.com/geaozhang/p/7341333.html#flush" target="_blank" rel="noreferrer">flush_lru_list checkpoint</a></p><p>3、<a href="https://www.cnblogs.com/geaozhang/p/7341333.html#asflush" target="_blank" rel="noreferrer">async/sync flush checkpoint</a></p><p>4、<a href="https://www.cnblogs.com/geaozhang/p/7341333.html#dirty" target="_blank" rel="noreferrer">dirty page too much checkpoint</a></p></blockquote><p><strong>一、日常关注的问题</strong></p><p><img src="https://images2017.cnblogs.com/blog/1113510/201708/1113510-20170810195008183-1048725467.png" alt="img"></p><p>1、我们的日志生成速度？</p><p>1、每天生成多少日志、产生多少redo log</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; show global status like &#39;Innodb_os_log_written&#39;;</span></span>
<span class="line"><span>+-----------------------+--------+</span></span>
<span class="line"><span>| Variable_name         | Value  |</span></span>
<span class="line"><span>+-----------------------+--------+</span></span>
<span class="line"><span>| Innodb_os_log_written | 107008 |</span></span>
<span class="line"><span>+-----------------------+--------+</span></span>
<span class="line"><span>1 row in set (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>2、如果redolog量大，需要修改如下参数，增加logfile的大小和组数</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; show variables like &#39;i%log_file%&#39;;</span></span>
<span class="line"><span>+---------------------------+----------+</span></span>
<span class="line"><span>| Variable_name             | Value    |</span></span>
<span class="line"><span>+---------------------------+----------+</span></span>
<span class="line"><span>| innodb_log_file_size      | 50331648 |</span></span>
<span class="line"><span>| innodb_log_files_in_group | 2        |</span></span>
<span class="line"><span>+---------------------------+----------+</span></span>
<span class="line"><span>2 rows in set (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>2、日志写入速度？</p><p>Log buffer有没有满、满的话为什么满</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; show variables like &#39;i%log_buffer%&#39;;</span></span>
<span class="line"><span>+------------------------+----------+</span></span>
<span class="line"><span>| Variable_name          | Value    |</span></span>
<span class="line"><span>+------------------------+----------+</span></span>
<span class="line"><span>| innodb_log_buffer_size | 16777216 |</span></span>
<span class="line"><span>+------------------------+----------+</span></span>
<span class="line"><span>1 row in set (0.01 sec)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>mysql&gt; show global status like &#39;%log_pending%&#39;;</span></span>
<span class="line"><span>+------------------------------+-------+</span></span>
<span class="line"><span>| Variable_name                | Value |</span></span>
<span class="line"><span>+------------------------------+-------+</span></span>
<span class="line"><span>| Innodb_os_log_pending_fsyncs | 0     |</span></span>
<span class="line"><span>| Innodb_os_log_pending_writes | 0     |</span></span>
<span class="line"><span>+------------------------------+-------+</span></span>
<span class="line"><span>2 rows in set (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>3、脏页的写入速度？</p><p>1、Log buffer满了会hang住</p><p>2、Logfile满了不能被覆盖也会hang住</p><p>3、如果脏页写入速度慢的话，logfile满了也不能被覆盖，系统容易hang住，log buffer如果满了的话也容易hang住。</p><p>4、数据库启动时间是多少？</p><p>启动时，默认是要先恢复脏页。当然，能通过参数innodb_force_recovery启动控制。</p><p>如果innodb_buffer_pool很大，32G，极端情况可能有32G的脏页，这个时候如果崩了，恢复的话需要恢复这32G的脏页，时间非常长。</p><p><strong>二、日志点分析</strong></p><p>通过show engine innodb status\\G解释一下LOG相关的四行参数的值：</p><p>Log sequence number 143942609---LSN：日志序列号(1)</p><p>//字节，日志生成的最新位置，最新位置出现在log buffer中</p><p>Log flushed up to 143942609---(2)</p><p>//字节，日志已经写入到log file的位置，1-2=log buffer日志量，最好是&lt;=1M</p><p>Pages flushed up to 143942609---(3)</p><p>//字节，脏页的数量(日志字节数来衡量)，2-3=脏页的数量(日志字节为单位)</p><p>Last checkpoint at 143942600---(4)</p><p>//字节，共享表空间上的日志记录点，最后一次检查点，及崩溃恢复时指定的起点，3-4就是崩溃恢复多跑的日志，值越大说明需要提升checkpoint的跟进速度</p><p><img src="https://images2017.cnblogs.com/blog/1113510/201708/1113510-20170810200645964-1913073767.png" alt="img"></p><p><strong>三、checkpoint</strong></p><p>检查点，表示脏页写入到磁盘的时候，所以检查点也就意味着脏数据的写入。</p><p>1、checkpoint的目的</p><p>1、缩短数据库的恢复时间</p><p>2、buffer pool空间不够用时，将脏页刷新到磁盘</p><p>3、redolog不可用时，刷新脏页</p><p>2、检查点分类</p><p>1、sharp checkpoint：完全检查点，数据库正常关闭时，会触发把所有的脏页都写入到磁盘上(这时候logfile的日志就没用了，脏页已经写到磁盘上了)。</p><p>1、完全检查点，发生在数据库正常关闭的时候。</p><p>2、在数据库在运行时不会使用sharp checkpoint，在引擎内部使用fuzzy checkpoint，即只刷新一部分脏页，而不是刷新所有的脏页回磁盘。</p><p>2、fuzzy checkpoint：模糊检查点，部分页写入磁盘。</p><p>1、发生在数据库正常运行期间。</p><p>2、模糊检查点，不是sharp的就是模糊检查点(4种)：master thread checkpoint、flush_lru_list checkpoint、async/sync flush checkpoint、dirty page too much checkpoint。</p><p><strong>四、fuzzy checkpoint发生的4个条件</strong></p><p>模糊检查点的发生，也就是脏页写入磁盘的情况。</p><p>1、master thread checkpoint</p><p>差不多以每秒或每十秒的速度从缓冲池的脏页列表中刷新一定比例的页回磁盘，这个过程是异步的，不会阻塞用户查询。</p><p>1、周期性，读取flush list，找到脏页，写入磁盘</p><p>2、写入的量比较小</p><p>3、异步，不影响业务</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; show variables like &#39;%io_cap%&#39;;</span></span>
<span class="line"><span>+------------------------+-------+</span></span>
<span class="line"><span>| Variable_name          | Value |</span></span>
<span class="line"><span>+------------------------+-------+</span></span>
<span class="line"><span>| innodb_io_capacity     | 200   |</span></span>
<span class="line"><span>| innodb_io_capacity_max | 2000  |</span></span>
<span class="line"><span>+------------------------+-------+</span></span>
<span class="line"><span>2 rows in set (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>4、通过capacity能力告知进行刷盘控制</p><p>通过innodb的io能力告知控制对flush list刷脏页数量，io_capacity越高，每次刷盘写入脏页数越多；</p><p>如果脏页数量过多，刷盘速度很慢，在io能力允许的情况下，调高innodb_io_capacity值，让多刷脏页。</p><p>2、flush_lru_list checkpoint</p><p>MySQL会保证，保证里面有多少可用的空闲页，在innodb 1.1.x版本之前，需要检查在用户查询线程中是否有足够的可用空间(差不多100个空闲页)，显然这会阻塞用户线程，如果没有100个可用空闲页，那么innodbhi将lru列表尾端的页移除，如果这些页中有脏页，那么需要进行checkpoint。Innodb 1.2(5.6)之后把他单独放到一个线程page cleaner中进行，用户可以通过参数innodb_lru_scan_depth控制lru列表中可用页的数量，默认是1024。</p><p>读取lru list，找到脏页，写入磁盘。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; show variables like &#39;%lru%depth&#39;;</span></span>
<span class="line"><span>+-----------------------+-------+</span></span>
<span class="line"><span>| Variable_name         | Value |</span></span>
<span class="line"><span>+-----------------------+-------+</span></span>
<span class="line"><span>| innodb_lru_scan_depth | 1024  |</span></span>
<span class="line"><span>+-----------------------+-------+</span></span>
<span class="line"><span>1 row in set (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>此情况下触发，默认扫描1024个lru冷端数据页，将脏页写入磁盘(有10个就刷10，有100个就刷100个……)</p><p>3、async/sync flush checkpoint</p><p>log file快满了，会批量的触发数据页回写，这个事件触发的时候又分为异步和同步，不可被覆盖的redolog占log file的比值：75%---&gt;异步、90%---&gt;同步。</p><p>当这两个事件中的任何一个发生的时候，都会记录到errlog中，一旦errlog出现这种日志提示，一定需要加大logfile。</p><p>Async/Sync Flush Checkpoint是为了保证重做日志的循环使用的可用性。在InnoDB 1.2.x版本之前，Async Flush Checkpoint会阻塞发现问题的用户查询线程，而Sync Flush Checkpoint会阻塞所有的用户查询线程，并且等待脏页刷新完成。从InnoDB 1.2.x版本开始——也就是MySQL 5.6版本，这部分的刷新操作同样放入到了单独的Page Cleaner Thread中，故不会阻塞用户查询线程。</p><p>4、dirty page too much checkpoint</p><p>很明显，脏页太多检查点，为了保证buffer pool的空间可用性的一个检查点。</p><p>1、脏页监控，关注点</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; show global status like &#39;Innodb_buffer_pool_pages%t%&#39;;</span></span>
<span class="line"><span>+--------------------------------+-------+</span></span>
<span class="line"><span>| Variable_name                  | Value |</span></span>
<span class="line"><span>+--------------------------------+-------+</span></span>
<span class="line"><span>| Innodb_buffer_pool_pages_data  | 2964  |</span></span>
<span class="line"><span>| Innodb_buffer_pool_pages_dirty | 0     |</span></span>
<span class="line"><span>| Innodb_buffer_pool_pages_total | 8191  |</span></span>
<span class="line"><span>+--------------------------------+-------+</span></span>
<span class="line"><span>3 rows in set (0.00 sec)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>mysql&gt; show global status like &#39;%wait_free&#39;;</span></span>
<span class="line"><span>+------------------------------+-------+</span></span>
<span class="line"><span>| Variable_name                | Value |</span></span>
<span class="line"><span>+------------------------------+-------+</span></span>
<span class="line"><span>| Innodb_buffer_pool_wait_free | 0     |</span></span>
<span class="line"><span>+------------------------------+-------+</span></span>
<span class="line"><span>1 row in set (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>1、Innodb_buffer_pool_pages_dirty/Innodb_buffer_pool_pages_total：表示脏页在buffer 的占比</p><p>2、Innodb_buffer_pool_wait_free：如果&gt;0，说明出现性能负载，buffer pool中没有干净可用块</p><p>2、脏页控制参数</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; show variables like &#39;%dirty%pct%&#39;;</span></span>
<span class="line"><span>+--------------------------------+-----------+</span></span>
<span class="line"><span>| Variable_name                  | Value     |</span></span>
<span class="line"><span>+--------------------------------+-----------+</span></span>
<span class="line"><span>| innodb_max_dirty_pages_pct     | 75.000000 |</span></span>
<span class="line"><span>| innodb_max_dirty_pages_pct_lwm | 0.000000  |</span></span>
<span class="line"><span>+--------------------------------+-----------+</span></span>
<span class="line"><span>2 rows in set (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>1、默认是脏页占比75%的时候，就会触发刷盘，将脏页写入磁盘，腾出内存空间。建议不调，调太低的话，io压力就会很大，但是崩溃恢复就很快；</p><p>2、lwm：low water mark低水位线，刷盘到该低水位线就不写脏页了，0也就是不限制。</p><p>注意：上面在调整的时候，要关注系统的写性能iostat -x。</p>`,74),i=[l];function r(c,o,t,b,u,h){return a(),n("div",null,i)}const d=s(e,[["render",r]]);export{g as __pageData,d as default};
